/**
 * rehype-no-autolink-email.mjs
 *
 * Unwraps auto-linked email addresses (mailto: links generated by GFM)
 * back into plain text. Only targets auto-generated links where the
 * link text matches the mailto address exactly.
 */
import { visit } from 'unist-util-visit';

export function rehypeNoAutolinkEmail() {
  return (tree) => {
    visit(tree, 'element', (node, index, parent) => {
      if (
        node.tagName !== 'a' ||
        !node.properties?.href?.startsWith('mailto:') ||
        !parent ||
        index == null
      ) return;

      const email = node.properties.href.slice(7);
      const text = node.children?.[0];
      if (text?.type === 'text' && text.value === email) {
        parent.children.splice(index, 1, { type: 'text', value: email });
        return index;
      }
    });
  };
}
